CREATE EXTENSION IF NOT EXISTS "pgcrypto";

CREATE TABLE "users" ("id" UUID PRIMARY KEY DEFAULT gen_random_uuid(), "loginId" VARCHAR(100) NOT NULL UNIQUE, "name" VARCHAR(100) NOT NULL, "password_hash" VARCHAR(100) NOT NULL, "role" VARCHAR(20) NOT NULL DEFAULT 'user', "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "companies" ("id" UUID PRIMARY KEY DEFAULT gen_random_uuid(), "name" VARCHAR(200) NOT NULL, "legal_form" VARCHAR(20) NOT NULL, "representative_name" VARCHAR(100), "email" VARCHAR(254), "phone" VARCHAR(30), "postal_code" VARCHAR(12), "address" VARCHAR(500), "corporate_number" VARCHAR(13), "closing_month" INTEGER NOT NULL, "schedule_dirty_at" TIMESTAMPTZ(3), "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "companies_legal_form_check" CHECK ("legal_form" IN ('corporation','sole_proprietor')), CONSTRAINT "companies_closing_month_check" CHECK ("closing_month" BETWEEN 1 AND 12));
CREATE TABLE "memberships" ("user_id" UUID NOT NULL REFERENCES "users"("id") ON DELETE CASCADE, "company_id" UUID NOT NULL REFERENCES "companies"("id") ON DELETE CASCADE, "role_in_company" VARCHAR(20) NOT NULL DEFAULT 'member', "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY ("user_id","company_id"), CONSTRAINT "memberships_role_check" CHECK ("role_in_company" IN ('owner','admin','member','accountant')));
CREATE INDEX "memberships_company_id_idx" ON "memberships"("company_id");
CREATE TABLE "sessions" ("id" UUID PRIMARY KEY DEFAULT gen_random_uuid(), "token_hash" VARCHAR(64) NOT NULL UNIQUE, "user_id" UUID NOT NULL REFERENCES "users"("id") ON DELETE CASCADE, "active_company_id" UUID REFERENCES "companies"("id") ON DELETE SET NULL, "expires_at" TIMESTAMPTZ(3) NOT NULL, "last_accessed_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX "sessions_user_id_idx" ON "sessions"("user_id"); CREATE INDEX "sessions_expires_at_idx" ON "sessions"("expires_at");
CREATE TABLE "company_tax_settings" ("company_id" UUID PRIMARY KEY REFERENCES "companies"("id") ON DELETE CASCADE, "is_taxable" BOOLEAN NOT NULL DEFAULT false, "withholding_special" BOOLEAN NOT NULL DEFAULT false, "resident_tax_special" BOOLEAN NOT NULL DEFAULT false, "previous_corporate_tax_yen" BIGINT, "previous_consumption_tax_yen" BIGINT, "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "company_recurring_tax_due_dates" ("id" UUID PRIMARY KEY DEFAULT gen_random_uuid(), "company_id" UUID NOT NULL REFERENCES "companies"("id") ON DELETE CASCADE, "title" VARCHAR(200) NOT NULL, "tax_type" VARCHAR(50) NOT NULL, "installment_label" VARCHAR(50), "month" INTEGER NOT NULL, "day" INTEGER NOT NULL, "enabled" BOOLEAN NOT NULL DEFAULT true, "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "recurring_month_check" CHECK ("month" BETWEEN 1 AND 12), CONSTRAINT "recurring_day_check" CHECK ("day" BETWEEN 1 AND 31));
CREATE INDEX "company_recurring_company_idx" ON "company_recurring_tax_due_dates"("company_id");
CREATE TABLE "tasks" ("id" UUID PRIMARY KEY DEFAULT gen_random_uuid(), "company_id" UUID NOT NULL REFERENCES "companies"("id") ON DELETE CASCADE, "task_key" VARCHAR(255), "title" VARCHAR(300) NOT NULL, "category" VARCHAR(30) NOT NULL, "due_date" DATE NOT NULL, "period_start" DATE, "period_end" DATE, "status" VARCHAR(20) NOT NULL DEFAULT 'pending', "generated" BOOLEAN NOT NULL DEFAULT true, "rule_version" VARCHAR(40) NOT NULL DEFAULT 'clas-asis-1', "completed_at" TIMESTAMPTZ(3), "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "tasks_status_check" CHECK ("status" IN ('pending','done','overdue')));
CREATE UNIQUE INDEX "tasks_company_task_key_key" ON "tasks"("company_id","task_key"); CREATE INDEX "tasks_company_due_idx" ON "tasks"("company_id","due_date");
CREATE TABLE "task_reminder_deliveries" ("id" UUID PRIMARY KEY DEFAULT gen_random_uuid(), "task_id" UUID NOT NULL REFERENCES "tasks"("id") ON DELETE CASCADE, "channel" VARCHAR(20) NOT NULL DEFAULT 'email', "remind_key" VARCHAR(40) NOT NULL, "status" VARCHAR(20) NOT NULL, "error_code" VARCHAR(80), "sent_at" TIMESTAMPTZ(3), "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE ("task_id","channel","remind_key"));
CREATE INDEX "task_reminder_created_idx" ON "task_reminder_deliveries"("created_at");
CREATE TABLE "accounting_checklist_items" ("id" UUID PRIMARY KEY DEFAULT gen_random_uuid(), "company_id" UUID NOT NULL REFERENCES "companies"("id") ON DELETE CASCADE, "name" VARCHAR(100) NOT NULL, "position" INTEGER NOT NULL DEFAULT 0, "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE ("company_id","name"));
CREATE INDEX "checklist_items_company_position_idx" ON "accounting_checklist_items"("company_id","position");
CREATE TABLE "accounting_checklist_checks" ("id" UUID PRIMARY KEY DEFAULT gen_random_uuid(), "company_id" UUID NOT NULL REFERENCES "companies"("id") ON DELETE CASCADE, "item_id" UUID NOT NULL REFERENCES "accounting_checklist_items"("id") ON DELETE CASCADE, "fiscal_year" INTEGER NOT NULL, "month" INTEGER NOT NULL, "checked" BOOLEAN NOT NULL DEFAULT false, "updated_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE ("company_id","item_id","fiscal_year","month"), CONSTRAINT "check_year_check" CHECK ("fiscal_year" BETWEEN 2000 AND 2100), CONSTRAINT "check_month_check" CHECK ("month" BETWEEN 1 AND 12));
CREATE INDEX "checklist_checks_company_year_idx" ON "accounting_checklist_checks"("company_id","fiscal_year");
CREATE TABLE "upload_grants" ("id" UUID PRIMARY KEY DEFAULT gen_random_uuid(), "company_id" UUID NOT NULL REFERENCES "companies"("id") ON DELETE CASCADE, "user_id" UUID NOT NULL REFERENCES "users"("id") ON DELETE CASCADE, "purpose" VARCHAR(30) NOT NULL, "file_name" VARCHAR(255) NOT NULL, "mime_type" VARCHAR(120) NOT NULL, "size" INTEGER NOT NULL, "expires_at" TIMESTAMPTZ(3) NOT NULL, "consumed_at" TIMESTAMPTZ(3), "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "upload_grants_purpose_check" CHECK ("purpose" IN ('rating','trial_balance')));
CREATE INDEX "upload_grants_company_expiry_idx" ON "upload_grants"("company_id","expires_at");
CREATE TABLE "uploads" ("id" UUID PRIMARY KEY DEFAULT gen_random_uuid(), "company_id" UUID NOT NULL REFERENCES "companies"("id") ON DELETE CASCADE, "user_id" UUID NOT NULL REFERENCES "users"("id") ON DELETE RESTRICT, "purpose" VARCHAR(30) NOT NULL, "original_name" VARCHAR(255) NOT NULL, "mime_type" VARCHAR(120) NOT NULL, "size" INTEGER NOT NULL, "sha256" VARCHAR(64), "storage_provider" VARCHAR(40) NOT NULL DEFAULT 'local_private', "storage_key" VARCHAR(1000) NOT NULL, "storage_url" VARCHAR(2000) NOT NULL, "access_mode" VARCHAR(20) NOT NULL DEFAULT 'private', "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE ("company_id","storage_provider","storage_key"), CONSTRAINT "uploads_purpose_check" CHECK ("purpose" IN ('rating','trial_balance')));
CREATE INDEX "uploads_company_purpose_idx" ON "uploads"("company_id","purpose");
CREATE TABLE "ratings" ("id" UUID PRIMARY KEY DEFAULT gen_random_uuid(), "upload_id" UUID NOT NULL UNIQUE REFERENCES "uploads"("id") ON DELETE CASCADE, "company_id" UUID NOT NULL REFERENCES "companies"("id") ON DELETE CASCADE, "score" INTEGER NOT NULL, "grade" VARCHAR(2) NOT NULL, "ai_comment" TEXT NOT NULL, "highlights" TEXT[] NOT NULL, "ai_source" VARCHAR(30) NOT NULL DEFAULT 'fallback', "score_version" VARCHAR(30) NOT NULL DEFAULT 'metadata-v1', "prompt_version" VARCHAR(30) NOT NULL DEFAULT 'rating-ja-v1', "model_version" VARCHAR(100), "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX "ratings_company_idx" ON "ratings"("company_id");
CREATE TABLE "emails" ("id" UUID PRIMARY KEY DEFAULT gen_random_uuid(), "company_id" UUID NOT NULL REFERENCES "companies"("id") ON DELETE CASCADE, "user_id" UUID NOT NULL REFERENCES "users"("id") ON DELETE RESTRICT, "recipient" VARCHAR(254) NOT NULL, "subject" VARCHAR(200) NOT NULL, "body" TEXT NOT NULL, "attachment_upload_ids" UUID[] NOT NULL, "idempotency_key" VARCHAR(100) NOT NULL, "status" VARCHAR(20) NOT NULL DEFAULT 'queued', "provider_message_id" VARCHAR(255), "error_code" VARCHAR(80), "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "sent_at" TIMESTAMPTZ(3), UNIQUE ("company_id","idempotency_key"));
CREATE INDEX "emails_company_created_idx" ON "emails"("company_id","created_at");
CREATE TABLE "manual_documents" ("id" UUID PRIMARY KEY DEFAULT gen_random_uuid(), "slug" VARCHAR(120) NOT NULL UNIQUE, "title" VARCHAR(200) NOT NULL, "content" TEXT NOT NULL, "published" BOOLEAN NOT NULL DEFAULT true, "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "audit_logs" ("id" UUID PRIMARY KEY DEFAULT gen_random_uuid(), "company_id" UUID, "actor_user_id" UUID, "action" VARCHAR(100) NOT NULL, "entity_type" VARCHAR(80) NOT NULL, "entity_id" VARCHAR(100), "result" VARCHAR(30) NOT NULL, "metadata" JSONB, "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX "audit_company_created_idx" ON "audit_logs"("company_id","created_at"); CREATE INDEX "audit_actor_created_idx" ON "audit_logs"("actor_user_id","created_at");
